import React from 'react';
import './Hero.scss';

const Hero = () => {
    const handleScrollToSection = () => {
        const section = document.getElementById('build-section');
        if (section) {
            section.scrollIntoView({ behavior: 'smooth' });
        }
    };

    return (
        <section className="hero">
            <div className="container">
                <h1>Создавайте здания по описанию со <span>Structo</span></h1>
                <p>Введите параметры и получите визуальную модель здания в 2D и 3D.
                    <br/>
                    Быстро, просто, интуитивно.
                </p>
                
                <button className="btn" onClick={handleScrollToSection}>Начать бесплатно</button>
            </div>
        </section>
    );
};

export default Hero;
