import React, { useState } from 'react'
import './Features.scss'
import '../adaptation.scss'

const features = [
    {
      title: "Удобный интерфейс",
      description: "Интуитивно понятный интерфейс позволит вам быстро настроить параметры здания и моментально увидеть результаты в 2D и 3D. Внесение изменений не требует специальных знаний.",
      image: "/Structo/img/features/features-1.jpg"
    },
    {
      title: "Гибкость и настраиваемость",
      description: "Настройте параметры здания по вашему усмотрению. Меняйте высоту, ширину, этажность и другие характеристики, создавая уникальные модели.",
      image: "/Structo/img/features/features-2.jpg"
    },
    {
      title: "Мгновенная визуализация",
      description: "Все изменения, внесенные в параметры здания, мгновенно отображаются в визуальной модели, что позволяет наглядно оценить результат и скорректировать его в реальном времени.",
      image: "/Structo/img/features/features-3.jpg"
    }
];

export default function Features() {
  const [selectedFeature, setSelectedFeature] = useState(0)

  return (
    <section className="features-section">
      <div className="features container">
        <div className="features-content">
          <div className="features-text">
            {features.map((feature, index) => (
              <div 
                key={index} 
                className={`feature-item ${selectedFeature === index ? 'active' : ''}`}
                onClick={() => setSelectedFeature(index)}
              >
                <h2 className="feature-title">{feature.title}</h2>
                <p className="feature-description">{feature.description}</p>
              </div>
            ))}
          </div>
          <div className="features-image">
            {features.map((feature, index) => (
              <img
                key={index}
                src={feature.image}
                alt={feature.title}
                className={`feature-img ${selectedFeature === index ? 'active' : ''}`}
              />
            ))}
          </div>
        </div>
      </div>
    </section>
  )
}