import React from 'react';
import { useNavigate } from 'react-router-dom';

import './Build.scss';
import '../adaptation.scss';

const Build = () => {
  const navigate = useNavigate();

  const handleGenerateClick = () => {
    navigate('/Generator');
  };

  return (
    <section className="build-section" id="build-section">
      <div className="container">
        <div className='build-title'>
          <h1 className="title">Создайте свое здание</h1>
          <p className="subtitle">
            Введите параметры вашего здания и увидите результат в реальном времени.
          </p>
        </div>

        <div className="build-button">
          <button type="button" className="submit-btn" onClick={handleGenerateClick}>
            Сгенерировать
          </button>
        </div>
      </div>
    </section>
  );
};

export default Build;
