function parsePositiveFloat(value) {
  const number = parseFloat(value);
  return Number.isFinite(number) && number > 0 ? number : null;
}

function parsePositiveInt(value) {
  const number = parseInt(value, 10);
  return Number.isInteger(number) && number > 0 ? number : null;
}

function clampNumber(value, min, max) {
  return Math.min(Math.max(value, min), max);
}

function pickPromptNumber(prompt, patterns, fallback) {
  for (const pattern of patterns) {
    const match = prompt.match(pattern);
    if (match) {
      const value = parseFloat(match[1].replace(',', '.'));
      if (Number.isFinite(value)) {
        return value;
      }
    }
  }

  return fallback;
}

function generateLocalBuildingConfig(prompt) {
  const compact = prompt.trim().toLowerCase().replace(/\s+/g, ' ');
  const sizeMatch = compact.match(/(\d+(?:[.,]\d+)?)\s*(?:x|х|\*|на)\s*(\d+(?:[.,]\d+)?)/);
  const small = /небольш|маленьк|компакт|мини|коттедж/.test(compact);
  const large = /больш|крупн|просторн|комплекс|кампус|многофункц/.test(compact);
  const tall = /высок|башн|многоэтаж|небоскреб|высот/.test(compact);
  const defaultWidth = small ? 10 : large ? 32 : 18;
  const defaultDepth = small ? 8 : large ? 24 : 14;
  const defaultFloors = small ? 2 : tall ? 24 : large ? 10 : 6;
  const widthValue = sizeMatch ? parseFloat(sizeMatch[1].replace(',', '.')) : pickPromptNumber(compact, [/ширин[аы]?\s*(\d+(?:[.,]\d+)?)/, /(\d+(?:[.,]\d+)?)\s*м\s*ширин/], defaultWidth);
  const depthValue = sizeMatch ? parseFloat(sizeMatch[2].replace(',', '.')) : pickPromptNumber(compact, [/глубин[аы]?\s*(\d+(?:[.,]\d+)?)/, /длин[аы]?\s*(\d+(?:[.,]\d+)?)/], defaultDepth);
  const floorHeight = pickPromptNumber(compact, [/высот[аы]?\s*этажа\s*(\d+(?:[.,]\d+)?)/, /этаж\s*по\s*(\d+(?:[.,]\d+)?)/], /лофт|атриум|премиум|обществен/.test(compact) ? 3.8 : 3.1);
  const floorsValue = pickPromptNumber(compact, [/(\d+)\s*(?:этаж|этажа|этажей)/, /на\s*(\d+)\s*(?:этаж|этажа|этажей)/], defaultFloors);

  let buildingType = 'residential';
  if (/офис|бизнес|коворкинг|делов|штаб/.test(compact)) buildingType = 'office';
  if (/магазин|торгов|коммерц|кафе|ресторан|ритейл|молл|бутик/.test(compact)) buildingType = 'retail';
  if (/завод|склад|ангар|производ|индустр|логист/.test(compact)) buildingType = 'industrial';

  let planShape = 'rectangle';
  if (/l[-\s]?план|г-образ|углов|ломан/.test(compact)) planShape = 'lShape';
  if (/u[-\s]?план|п-образ|двор|внутренний двор|курдонер/.test(compact)) planShape = 'uShape';

  let roofType = 'flat';
  if (/двускат|скатн|коттедж|домик|шале|классичес/.test(compact)) roofType = 'gable';
  if (/пирамид|шатров|павильон/.test(compact)) roofType = 'pyramid';

  let facadeMaterial = 'concrete';
  if (/стекл|витраж|панорам|прозрач|hi-tech|хайтек/.test(compact)) facadeMaterial = 'glass';
  if (/кирпич|лофт/.test(compact)) facadeMaterial = 'brick';
  if (/дерев|брус|timber|эко/.test(compact)) facadeMaterial = 'wood';

  const hasBalconies = !/(без балкон|балконы не|нет балкон)/.test(compact) && /балкон|лоджи|жил|апартамент|квартир|террас/.test(compact);
  const hasLandscape = !/(без окруж|без дерев|без ландшафт|пустая площадка)/.test(compact);
  const showGrid = !/(без сетк|сетку не)/.test(compact);
  const styleDensity = /много окон|плотн|детальн|витраж|панорам|стекл|сложн/.test(compact) ? 'dense' : 'balanced';

  return {
    width: clampNumber(widthValue, 4, 120),
    height: clampNumber(floorHeight, 2.2, 7),
    depth: clampNumber(depthValue, 4, 120),
    floors: clampNumber(Math.round(floorsValue), 1, 80),
    buildingType,
    planShape,
    roofType,
    facadeMaterial,
    styleDensity,
    hasBalconies,
    hasLandscape,
    showGrid,
    designNotes: 'Локальный генератор построил модель по ключевым архитектурным признакам промпта.',
  };
}

async function requestAiBuildingConfig(prompt) {
  const response = await fetch(`${apiBaseUrl}/api/generate-building`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({ prompt }),
  });

  const payload = await response.json().catch(() => ({}));

  if (!response.ok) {
    throw new Error(payload.error || payload.details || 'Нейросеть временно недоступна.');
  }

  return payload;
}

function getPlanSegments(width, depth, planShape) {
  if (planShape === 'lShape') {
    return [
      { x: -width * 0.18, z: 0, width: width * 0.64, depth },
      { x: width * 0.26, z: depth * 0.2, width: width * 0.36, depth: depth * 0.6 },
    ];
  }

  if (planShape === 'uShape') {
    return [
      { x: 0, z: depth * 0.28, width, depth: depth * 0.44 },
      { x: -width * 0.32, z: -depth * 0.12, width: width * 0.36, depth: depth * 0.64 },
      { x: width * 0.32, z: -depth * 0.12, width: width * 0.36, depth: depth * 0.64 },
    ];
  }

  return [{ x: 0, z: 0, width, depth }];
}

function createWindowGrid(group, segment, config, preset, floorIndex) {
  const { height, styleDensity } = config;
  const floorY = floorIndex * height + height * 0.58;
  const rows = Math.max(1, Math.floor(segment.width / (styleDensity === 'dense' ? 2.2 : 3.1)));
  const columns = Math.max(1, Math.floor(segment.depth / (styleDensity === 'dense' ? 2.4 : 3.4)));
  const windowMaterial = new THREE.MeshStandardMaterial({
    color: config.facadeMaterial === 'glass' ? 0xc8f4ff : 0x9fd0df,
    metalness: 0.1,
    roughness: 0.22,
    transparent: true,
    opacity: 0.78,
  });
  const frameMaterial = new THREE.MeshStandardMaterial({ color: preset.accent, roughness: 0.55 });
  const windowWidth = Math.min(0.8, segment.width / (rows * 2.2));
  const windowHeight = Math.min(height * 0.38, 1.1);

  const addWindow = (x, y, z, rotationY = 0) => {
    const frame = new THREE.Mesh(new THREE.BoxGeometry(windowWidth + 0.12, windowHeight + 0.12, 0.08), frameMaterial);
    frame.position.set(x, y, z);
    frame.rotation.y = rotationY;
    group.add(frame);

    const glass = new THREE.Mesh(new THREE.BoxGeometry(windowWidth, windowHeight, 0.1), windowMaterial);
    glass.position.set(x, y, z + (rotationY === 0 ? 0.03 : 0));
    glass.rotation.y = rotationY;
    group.add(glass);
  };

  for (let i = 0; i < rows; i += 1) {
    const x = segment.x - segment.width / 2 + ((i + 1) * segment.width) / (rows + 1);
    addWindow(x, floorY, segment.z + segment.depth / 2 + 0.04);
    addWindow(x, floorY, segment.z - segment.depth / 2 - 0.04, Math.PI);
  }

  for (let i = 0; i < columns; i += 1) {
    const z = segment.z - segment.depth / 2 + ((i + 1) * segment.depth) / (columns + 1);
    addWindow(segment.x - segment.width / 2 - 0.04, floorY, z, Math.PI / 2);
    addWindow(segment.x + segment.width / 2 + 0.04, floorY, z, Math.PI / 2);
  }

  return (rows + columns) * 2;
}

function addRoof(group, config, segments, preset) {
  const { height, floors, roofType } = config;
  const totalHeight = height * floors;
  const roofMaterial = new THREE.MeshStandardMaterial({
    color: preset.accent,
    roughness: 0.62,
    metalness: 0.05,
  });

  segments.forEach((segment) => {
    if (roofType === 'flat') {
      const slab = new THREE.Mesh(new THREE.BoxGeometry(segment.width + 0.4, 0.22, segment.depth + 0.4), roofMaterial);
      slab.position.set(segment.x, totalHeight + 0.12, segment.z);
      group.add(slab);
      return;
    }

    if (roofType === 'gable') {
      const roofHeight = Math.max(0.7, config.height * 0.45);
      const shape = new THREE.Shape();
      shape.moveTo(-segment.width / 2 - 0.25, 0);
      shape.lineTo(0, roofHeight);
      shape.lineTo(segment.width / 2 + 0.25, 0);
      shape.lineTo(-segment.width / 2 - 0.25, 0);
      const geometry = new THREE.ExtrudeGeometry(shape, {
        depth: segment.depth + 0.5,
        bevelEnabled: false,
      });
      const roof = new THREE.Mesh(geometry, roofMaterial);
      roof.position.set(segment.x, totalHeight, segment.z - segment.depth / 2 - 0.25);
      group.add(roof);
      return;
    }

    const cone = new THREE.Mesh(
      new THREE.ConeGeometry(Math.max(segment.width, segment.depth) * 0.74, Math.max(1, config.height * 0.58), 4),
      roofMaterial,
    );
    cone.position.set(segment.x, totalHeight + Math.max(1, config.height * 0.58) / 2, segment.z);
    cone.rotation.y = Math.PI / 4;
    cone.scale.z = segment.depth / Math.max(segment.width, 0.1);
    group.add(cone);
  });
}

function addBalconies(group, segment, config, floorIndex) {
  if (!config.hasBalconies || floorIndex === 0) {
    return 0;
  }

  const balconyMaterial = new THREE.MeshStandardMaterial({ color: 0xe6edf2, roughness: 0.4, metalness: 0.2 });
  const railMaterial = new THREE.MeshStandardMaterial({ color: 0x4f5d66, roughness: 0.35, metalness: 0.35 });
  const count = Math.max(1, Math.floor(segment.width / 4));
  const y = floorIndex * config.height + config.height * 0.22;

  for (let i = 0; i < count; i += 1) {
    const x = segment.x - segment.width / 2 + ((i + 1) * segment.width) / (count + 1);
    const slab = new THREE.Mesh(new THREE.BoxGeometry(1.5, 0.12, 0.72), balconyMaterial);
    slab.position.set(x, y, segment.z + segment.depth / 2 + 0.36);
    group.add(slab);

    const rail = new THREE.Mesh(new THREE.BoxGeometry(1.55, 0.42, 0.06), railMaterial);
    rail.position.set(x, y + 0.28, segment.z + segment.depth / 2 + 0.72);
    group.add(rail);
  }

  return count;
}

function addEntrance(group, config, preset) {
  const doorMaterial = new THREE.MeshStandardMaterial({ color: 0x2d3438, roughness: 0.45 });
  const awningMaterial = new THREE.MeshStandardMaterial({ color: preset.accent, roughness: 0.5, metalness: 0.15 });
  const door = new THREE.Mesh(new THREE.BoxGeometry(1.35, Math.min(config.height * 0.72, 2.2), 0.12), doorMaterial);
  door.position.set(0, Math.min(config.height * 0.36, 1.1), config.depth / 2 + 0.08);
  group.add(door);

  const awning = new THREE.Mesh(new THREE.BoxGeometry(2.2, 0.16, 1.1), awningMaterial);
  awning.position.set(0, Math.min(config.height * 0.82, 2.45), config.depth / 2 + 0.55);
  group.add(awning);
}

function addSurroundings(group, config) {
  if (!config.hasLandscape) {
    return;
  }

  const ground = new THREE.Mesh(
    new THREE.PlaneGeometry(config.width * 2.3, config.depth * 2.3),
    new THREE.MeshStandardMaterial({ color: 0x9fb58d, roughness: 0.9 }),
  );
  ground.rotation.x = -Math.PI / 2;
  ground.position.y = -0.04;
  group.add(ground);

  const trunkMaterial = new THREE.MeshStandardMaterial({ color: 0x7a4b2a, roughness: 0.8 });
  const crownMaterial = new THREE.MeshStandardMaterial({ color: 0x4f8f5d, roughness: 0.7 });
  const positions = [
    [-config.width * 0.72, config.depth * 0.72],
    [config.width * 0.72, config.depth * 0.68],
    [-config.width * 0.72, -config.depth * 0.72],
    [config.width * 0.72, -config.depth * 0.68],
  ];

  positions.forEach(([x, z]) => {
    const trunk = new THREE.Mesh(new THREE.CylinderGeometry(0.08, 0.1, 0.75, 8), trunkMaterial);
    trunk.position.set(x, 0.35, z);
    group.add(trunk);

    const crown = new THREE.Mesh(new THREE.ConeGeometry(0.48, 1.2, 10), crownMaterial);
    crown.position.set(x, 1.15, z);
    group.add(crown);
  });
}

function createBuildingModel(config) {
  const group = new THREE.Group();
  const preset = materialPresets[config.facadeMaterial];
  const segments = getPlanSegments(config.width, config.depth, config.planShape);
  const facadeMaterial = new THREE.MeshStandardMaterial({
    color: preset.color,
    roughness: preset.roughness,
    metalness: config.facadeMaterial === 'glass' ? 0.24 : 0.04,
  });
  const edgeMaterial = new THREE.LineBasicMaterial({ color: preset.accent, transparent: true, opacity: 0.55 });
  let windows = 0;
  let balconies = 0;

  addSurroundings(group, config);

  segments.forEach((segment) => {
    for (let floorIndex = 0; floorIndex < config.floors; floorIndex += 1) {
      const geometry = new THREE.BoxGeometry(segment.width, config.height, segment.depth);
      const floor = new THREE.Mesh(geometry, facadeMaterial);
      floor.position.set(segment.x, floorIndex * config.height + config.height / 2, segment.z);
      group.add(floor);

      const edges = new THREE.LineSegments(new THREE.EdgesGeometry(geometry), edgeMaterial);
      edges.position.copy(floor.position);
      group.add(edges);

      windows += createWindowGrid(group, segment, config, preset, floorIndex);
      balconies += addBalconies(group, segment, config, floorIndex);
    }
  });

  addEntrance(group, config, preset);
  addRoof(group, config, segments, preset);

  group.userData = { windows, balconies };
  return group;
}

function downloadBlob(blob, filename) {
  const url = URL.createObjectURL(blob);
  const link = document.createElement('a');
  link.href = url;
  link.download = filename;
  link.click();
  URL.revokeObjectURL(url);
}

function Generator() {
  const [prompt, setPrompt] = useState('современный стеклянный офис 24x16 метров, 8 этажей, плоская крыша, много окон и деревья вокруг');
  const [width, setWidth] = useState('16');
  const [height, setHeight] = useState('3');
  const [depth, setDepth] = useState('12');
  const [floors, setFloors] = useState('5');
  const [buildingType, setBuildingType] = useState('residential');
  const [planShape, setPlanShape] = useState('rectangle');
  const [roofType, setRoofType] = useState('flat');
  const [facadeMaterial, setFacadeMaterial] = useState('concrete');
  const [styleDensity, setStyleDensity] = useState('balanced');
  const [hasBalconies, setHasBalconies] = useState(true);
  const [hasLandscape, setHasLandscape] = useState(true);
  const [showGrid, setShowGrid] = useState(true);
  const [result, setResult] = useState(null);
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [mode, setMode] = useState('3D');

  const sceneRef = useRef(null);
  const canvasRef = useRef(null);
  const rendererRef = useRef(null);
  const modelRef = useRef(null);

  const draftConfig = useMemo(() => ({
    width: parsePositiveFloat(width) || 0,
    height: parsePositiveFloat(height) || 0,
    depth: parsePositiveFloat(depth) || 0,
    floors: parsePositiveInt(floors) || 0,
    buildingType,
    planShape,
    roofType,
    facadeMaterial,
    styleDensity,
    hasBalconies,
    hasLandscape,
    showGrid,
  }), [width, height, depth, floors, buildingType, planShape, roofType, facadeMaterial, styleDensity, hasBalconies, hasLandscape, showGrid]);

  const validateInputs = (config) => {
    if (!config.width) throw new Error('Ширина должна быть положительным числом.');
    if (!config.height) throw new Error('Высота этажа должна быть положительным числом.');
    if (!config.depth) throw new Error('Глубина должна быть положительным числом.');
    if (!config.floors) throw new Error('Количество этажей должно быть положительным числом.');
    if (config.floors > 80) throw new Error('Для удобного просмотра укажите не больше 80 этажей.');
  };

  const buildResult = (config) => {
    const planSegments = getPlanSegments(config.width, config.depth, config.planShape);
    const floorArea = planSegments.reduce((sum, segment) => sum + segment.width * segment.depth, 0);
    const totalArea = floorArea * config.floors;
    const volume = totalArea * config.height;
    const preview = createBuildingModel(config);

    return {
      ...config,
      floorArea: floorArea.toFixed(2),
      totalArea: totalArea.toFixed(2),
      volume: volume.toFixed(2),
      windows: preview.userData.windows,
      balconies: preview.userData.balconies,
    };
  };

  const applyConfigToForm = (config) => {
    setWidth(String(config.width));
    setHeight(String(config.height));
    setDepth(String(config.depth));
    setFloors(String(config.floors));
    setBuildingType(config.buildingType);
    setPlanShape(config.planShape);
    setRoofType(config.roofType);
    setFacadeMaterial(config.facadeMaterial);
    setStyleDensity(config.styleDensity);
    setHasBalconies(config.hasBalconies);
    setHasLandscape(config.hasLandscape);
    setShowGrid(config.showGrid);
  };

  useEffect(() => {
    if (!result || mode !== '3D') {
      return undefined;
    }

    const container = sceneRef.current;
    if (!container) {
      return undefined;
    }

    const scene = new THREE.Scene();
    scene.background = new THREE.Color(0xf2f5f7);
    const widthPx = container.clientWidth || 520;
    const heightPx = container.clientHeight || 420;
    const camera = new THREE.PerspectiveCamera(48, widthPx / heightPx, 0.1, 2000);
    const renderer = new THREE.WebGLRenderer({ antialias: true, preserveDrawingBuffer: true });
    renderer.setSize(widthPx, heightPx);
    renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
    renderer.shadowMap.enabled = true;
    rendererRef.current = renderer;

    container.innerHTML = '';
    container.appendChild(renderer.domElement);

    const model = createBuildingModel(result);
    modelRef.current = model;
    scene.add(model);

    const ambient = new THREE.HemisphereLight(0xffffff, 0x8a9a8f, 1.25);
    scene.add(ambient);

    const sun = new THREE.DirectionalLight(0xffffff, 2);
    sun.position.set(result.width * 1.4, result.height * result.floors * 1.6, result.depth * 1.2);
    scene.add(sun);

    if (result.showGrid) {
      const grid = new THREE.GridHelper(Math.max(result.width, result.depth) * 2.4, 18, 0x5f6b72, 0xc2cbd1);
      scene.add(grid);
    }

    const totalHeight = result.height * result.floors;
    const radius = Math.max(result.width, result.depth, totalHeight) * 1.45;
    camera.position.set(radius, Math.max(totalHeight * 0.8, result.height * 4), radius);
    camera.lookAt(0, totalHeight / 2, 0);

    const controls = new OrbitControls(camera, renderer.domElement);
    controls.enableDamping = true;
    controls.dampingFactor = 0.08;
    controls.target.set(0, totalHeight / 2, 0);
    controls.update();

    let frameId;
    const animate = () => {
      frameId = requestAnimationFrame(animate);
      controls.update();
      renderer.render(scene, camera);
    };
    animate();

    const handleResize = () => {
      const nextWidth = container.clientWidth || widthPx;
      const nextHeight = container.clientHeight || heightPx;
      camera.aspect = nextWidth / nextHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(nextWidth, nextHeight);
    };
    window.addEventListener('resize', handleResize);

    return () => {
      cancelAnimationFrame(frameId);
      window.removeEventListener('resize', handleResize);
      controls.dispose();
      renderer.dispose();
      container.innerHTML = '';
      rendererRef.current = null;
      modelRef.current = null;
    };
  }, [result, mode]);

  useEffect(() => {
    if (!result || mode !== '2D') {
      return;
    }

    const canvas = canvasRef.current;
    if (!canvas) {
      return;
    }

    const ctx = canvas.getContext('2d');
    const rect = canvas.getBoundingClientRect();
    const scale = window.devicePixelRatio || 1;
    canvas.width = rect.width * scale;
    canvas.height = rect.height * scale;
    ctx.scale(scale, scale);
    ctx.clearRect(0, 0, rect.width, rect.height);

    const gradient = ctx.createLinearGradient(0, 0, rect.width, rect.height);
    gradient.addColorStop(0, '#f4f7f8');
    gradient.addColorStop(1, '#dce7e0');
    ctx.fillStyle = gradient;
    ctx.fillRect(0, 0, rect.width, rect.height);

    const padding = 46;
    const scaleToFit = Math.min((rect.width - padding * 2) / result.width, (rect.height - padding * 2) / result.depth);
    const centerX = rect.width / 2;
    const centerY = rect.height / 2;
    const segments = getPlanSegments(result.width, result.depth, result.planShape);

    ctx.strokeStyle = '#9aa8a0';
    ctx.lineWidth = 1;
    ctx.setLineDash([5, 6]);
    for (let x = padding; x < rect.width - padding; x += 28) {
      ctx.beginPath();
      ctx.moveTo(x, padding);
      ctx.lineTo(x, rect.height - padding);
      ctx.stroke();
    }
    for (let y = padding; y < rect.height - padding; y += 28) {
      ctx.beginPath();
      ctx.moveTo(padding, y);
      ctx.lineTo(rect.width - padding, y);
      ctx.stroke();
    }
    ctx.setLineDash([]);

    segments.forEach((segment) => {
      const x = centerX + (segment.x - segment.width / 2) * scaleToFit;
      const y = centerY + (segment.z - segment.depth / 2) * scaleToFit;
      const w = segment.width * scaleToFit;
      const h = segment.depth * scaleToFit;
      ctx.fillStyle = '#cfd7ce';
      ctx.strokeStyle = '#35424a';
      ctx.lineWidth = 3;
      ctx.fillRect(x, y, w, h);
      ctx.strokeRect(x, y, w, h);
    });

    ctx.fillStyle = '#263238';
    ctx.font = '600 14px Inter, Arial, sans-serif';
    ctx.fillText(`${shapeLabels[result.planShape]} | ${result.width} x ${result.depth} м`, padding, rect.height - 20);
  }, [result, mode]);

  const handleGenerate = (event) => {
    event.preventDefault();
    setLoading(true);
    setError('');

    try {
      validateInputs(draftConfig);
      window.setTimeout(() => {
        setResult(buildResult(draftConfig));
        setLoading(false);
      }, 350);
    } catch (err) {
      setError(err.message);
      setLoading(false);
    }
  };

  const handlePromptGenerate = async () => {
    setLoading(true);
    setError('');

    try {
      if (!prompt.trim()) {
        throw new Error('Опишите здание: тип, размеры, этажность, материал или форму.');
      }

      const aiResponse = await requestAiBuildingConfig(prompt.trim());
      const aiConfig = aiResponse.config;
      validateInputs(aiConfig);
      applyConfigToForm(aiConfig);

      window.setTimeout(() => {
        setResult({
          ...buildResult(aiConfig),
          sourcePrompt: prompt.trim(),
          aiModel: aiResponse.model,
          designNotes: aiConfig.designNotes,
        });
        setMode('3D');
        setLoading(false);
      }, 450);
    } catch (err) {
      const fallbackConfig = generateLocalBuildingConfig(prompt);
      applyConfigToForm(fallbackConfig);
      setResult({
        ...buildResult(fallbackConfig),
        sourcePrompt: prompt.trim(),
        aiModel: 'local-fallback',
        designNotes: fallbackConfig.designNotes,
      });
      setMode('3D');
      setError(`${err.message} Модель построена локально. Для Yandex AI Studio проверьте npm run server, YANDEX_API_KEY и YANDEX_FOLDER_ID.`);
      setLoading(false);
    }
  };

  const handleExportJson = () => {
    if (!result) return;
    downloadBlob(new Blob([JSON.stringify(result, null, 2)], { type: 'application/json' }), 'structo-model.json');
  };

  const handleExportPng = () => {
    const renderer = rendererRef.current;
    if (!renderer) return;
    renderer.domElement.toBlob((blob) => {
      if (blob) downloadBlob(blob, 'structo-preview.png');
    });
  };

  const handleExportGlb = () => {
    if (!result) return;
    const exporter = new GLTFExporter();
    const model = createBuildingModel(result);
    exporter.parse(
      model,
      (gltf) => {
        const blob = gltf instanceof ArrayBuffer
          ? new Blob([gltf], { type: 'model/gltf-binary' })
          : new Blob([JSON.stringify(gltf)], { type: 'model/gltf+json' });
        downloadBlob(blob, 'structo-model.glb');
      },
      (err) => setError(`Не удалось экспортировать GLB: ${err.message}`),
      { binary: true },
    );
  };

  return (
    <div className="generator-container">
      <div className="breadcrumbs">
        <Link to="/">Главная</Link> / <Link to="/generator">Генерация здания</Link>
      </div>

      <div className={`generator-content${result ? ' with-result' : ''}`}>
        <div className="generator-card">
          <div className="card-header">
            <div className="icon-container">
              <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="icon">
                <path d="M6 22V4a2 2 0 0 1 2-2h8a2 2 0 0 1 2 2v18H6Z" />
                <path d="M6 12H4a2 2 0 0 0-2 2v6a2 2 0 0 0 2 2h2" />
                <path d="M18 12h2a2 2 0 0 1 2 2v6a2 2 0 0 1-2 2h-2" />
                <path d="M10 16h4" />
              </svg>
            </div>
            <h1 className="card-title">Генерация здания</h1>
            <p className="card-description">Настройте габариты, форму, фасад и детали модели.</p>
          </div>

          <div className="card-content">
            <form onSubmit={handleGenerate} className="generator-form">
              <div className="prompt-panel">
                <div className="prompt-header">
                  <div>
                    <span className="prompt-kicker">AI генерация</span>
                    <label htmlFor="buildingPrompt">Опишите здание промптом</label>
                  </div>
                  <button type="button" className="prompt-generate-btn" onClick={handlePromptGenerate} disabled={loading}>
                    {loading ? 'Думаю...' : 'Сгенерировать по промпту'}
                  </button>
                </div>
                <textarea
                  id="buildingPrompt"
                  value={prompt}
                  onChange={(event) => setPrompt(event.target.value)}
                  rows="4"
                  placeholder="Например: кирпичный жилой дом 18x12 м, 6 этажей, двускатная крыша, балконы, L-план"
                />
              </div>

              <div className="form-grid">
                <div className="form-group">
                  <label htmlFor="width">Ширина, м</label>
                  <input id="width" type="number" min="1" step="0.1" value={width} onChange={(event) => setWidth(event.target.value)} required />
                </div>

                <div className="form-group">
                  <label htmlFor="height">Высота этажа, м</label>
                  <input id="height" type="number" min="1" step="0.1" value={height} onChange={(event) => setHeight(event.target.value)} required />
                </div>

                <div className="form-group">
                  <label htmlFor="depth">Глубина, м</label>
                  <input id="depth" type="number" min="1" step="0.1" value={depth} onChange={(event) => setDepth(event.target.value)} required />
                </div>

                <div className="form-group">
                  <label htmlFor="floors">Этажей</label>
                  <input id="floors" type="number" min="1" max="40" value={floors} onChange={(event) => setFloors(event.target.value)} required />
                </div>
              </div>

              <div className="form-grid">
                <div className="form-group">
                  <label htmlFor="buildingType">Назначение</label>
                  <select id="buildingType" value={buildingType} onChange={(event) => setBuildingType(event.target.value)}>
                    {Object.entries(typeLabels).map(([value, label]) => <option key={value} value={value}>{label}</option>)}
                  </select>
                </div>

                <div className="form-group">
                  <label htmlFor="planShape">Форма плана</label>
                  <select id="planShape" value={planShape} onChange={(event) => setPlanShape(event.target.value)}>
                    {Object.entries(shapeLabels).map(([value, label]) => <option key={value} value={value}>{label}</option>)}
                  </select>
                </div>

                <div className="form-group">
                  <label htmlFor="roofType">Крыша</label>
                  <select id="roofType" value={roofType} onChange={(event) => setRoofType(event.target.value)}>
                    {Object.entries(roofLabels).map(([value, label]) => <option key={value} value={value}>{label}</option>)}
                  </select>
                </div>

                <div className="form-group">
                  <label htmlFor="facadeMaterial">Материал</label>
                  <select id="facadeMaterial" value={facadeMaterial} onChange={(event) => setFacadeMaterial(event.target.value)}>
                    {Object.entries(materialPresets).map(([value, preset]) => <option key={value} value={value}>{preset.label}</option>)}
                  </select>
                </div>
              </div>

              <div className="form-group">
                <label>Детализация фасада</label>
                <div className="view-toggle">
                  <button type="button" className={`toggle-btn ${styleDensity === 'balanced' ? 'active' : ''}`} onClick={() => setStyleDensity('balanced')}>Сбалансированная</button>
                  <button type="button" className={`toggle-btn ${styleDensity === 'dense' ? 'active' : ''}`} onClick={() => setStyleDensity('dense')}>Плотная</button>
                </div>
              </div>

              <div className="option-row">
                <label className="checkbox-option">
                  <input type="checkbox" checked={hasBalconies} onChange={(event) => setHasBalconies(event.target.checked)} />
                  Балконы
                </label>
                <label className="checkbox-option">
                  <input type="checkbox" checked={hasLandscape} onChange={(event) => setHasLandscape(event.target.checked)} />
                  Окружение
                </label>
                <label className="checkbox-option">
                  <input type="checkbox" checked={showGrid} onChange={(event) => setShowGrid(event.target.checked)} />
                  Сетка
                </label>
              </div>

              <div className="form-group">
                <label>Режим просмотра</label>
                <div className="view-toggle">
                  <button type="button" className={`toggle-btn ${mode === '3D' ? 'active' : ''}`} onClick={() => setMode('3D')}>3D</button>
                  <button type="button" className={`toggle-btn ${mode === '2D' ? 'active' : ''}`} onClick={() => setMode('2D')}>2D план</button>
                </div>
              </div>

              {error && <div className="error-message">{error}</div>}

              <button type="submit" className="generate-btn" disabled={loading}>
                {loading ? 'Генерация...' : 'Сгенерировать модель'}
              </button>
            </form>
          </div>
        </div>

        <div className="scene-container">
          {result && (
            <div className="result-card">
              <div className="result-header">
                <h2 className="result-title">Результат генерации</h2>
                <div className="export-actions">
                  <button type="button" onClick={handleExportJson}>JSON</button>
                  <button type="button" onClick={handleExportGlb}>GLB</button>
                  <button type="button" onClick={handleExportPng} disabled={mode !== '3D'}>PNG</button>
                </div>
              </div>

              <div className="result-grid">
                {result.sourcePrompt && <div className="result-item result-item-wide"><span className="result-label">Промпт:</span><span className="result-value">{result.sourcePrompt}</span></div>}
                <div className="result-item"><span className="result-label">Тип:</span><span className="result-value">{typeLabels[result.buildingType]}</span></div>
                <div className="result-item"><span className="result-label">План:</span><span className="result-value">{shapeLabels[result.planShape]}</span></div>
                <div className="result-item"><span className="result-label">Крыша:</span><span className="result-value">{roofLabels[result.roofType]}</span></div>
                <div className="result-item"><span className="result-label">Площадь этажа:</span><span className="result-value">{result.floorArea} м2</span></div>
                <div className="result-item"><span className="result-label">Общая площадь:</span><span className="result-value">{result.totalArea} м2</span></div>
                <div className="result-item"><span className="result-label">Объем:</span><span className="result-value">{result.volume} м3</span></div>
                <div className="result-item"><span className="result-label">Окна:</span><span className="result-value">{result.windows}</span></div>
                <div className="result-item"><span className="result-label">Балконы:</span><span className="result-value">{result.balconies}</span></div>
              </div>

              <div className="visualization">
                {mode === '3D' ? <div ref={sceneRef} className="scene-3d" /> : <canvas ref={canvasRef} className="scene-2d" />}
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

export default Generator;
